y: 'base' }));\n}\n\n/**\n * List problems with optional filters and metadata.\n * @param {Object} query\n * @param {string} [query.difficulty]\n * @param {string|Array<string>} [query.tags]\n * @param {number|string} [query.limit]\n * @param {boolean|string} [query.includeComponents]\n * @returns {Promise<Object>} result\n */\nfunction* listProblems(query) {\n  // Validate and normalize inputs\n  const schema = Joi.object({\n    difficulty: Joi.string().valid('easy', 'medium', 'hard').optional(),\n    tags: Joi.alternatives().try"}], "localized": true}
